 87→fn detect_content_type(content: &str) -> &'static str {
 88→    let trimmed = content.trim();
 89→
 90→    if trimmed.starts_with("http://") || trimmed.starts_with("https://") {
 91→        return "link";
 92→    }
 93→
 94→    if (trimmed.len() == 4 || trimmed.len() == 7 || trimmed.len() == 9)
 95→        && trimmed.starts_with('#')
 96→        && trimmed[1..].chars().all(|c| c.is_ascii_hexdigit())
 97→    {
 98→        return "color";
 99→    }
100→
101→    if trimmed.starts_with("rgb(")
102→        || trimmed.starts_with("rgba(")
103→        || trimmed.starts_with("hsl(")
104→        || trimmed.starts_with("hsla(")
105→    {
106→        return "color";
107→    }
108→
109→    "text"
110→}
