151→#[derive(Serialize)]
152→struct FileEntryResult {
153→    id: String,
154→    name: String,
155→    path: String,
156→    #[serde(rename = "fileType")]
157→    file_type: String,
158→    size: u64,
159→    #[serde(rename = "modifiedAt")]
160→    modified_at: u64,
161→}
