319→#[tauri::command]
320→fn open_file(path: String) -> Result<(), String> {
321→    let p = std::path::Path::new(&path);
322→    if !is_path_within_home(p) {
323→        return Err(format!("path not allowed: {path}"));
324→    }
325→    open::that(&path).map_err(|e| format!("failed to open {path}: {e}"))
326→}
