328→#[tauri::command]
329→fn reveal_in_finder(path: String) -> Result<(), String> {
330→    let p = std::path::Path::new(&path);
331→    if !is_path_within_home(p) {
332→        return Err(format!("path not allowed: {path}"));
333→    }
334→
335→    #[cfg(target_os = "macos")]
336→    {
337→        let output = std::process::Command::new("open")
338→            .arg("-R")
339→            .arg(&path)
340→            .output()
341→            .map_err(|e| format!("failed to reveal {path}: {e}"))?;
342→        if !output.status.success() {
343→            let stderr = String::from_utf8_lossy(&output.stderr);
344→            return Err(format!("failed to reveal {path}: {stderr}"));
345→        }
346→        return Ok(());
347→    }
348→
349→    #[cfg(target_os = "windows")]
350→    {
351→        let output = std::process::Command::new("explorer")
352→            .arg(format!("/select,{}", &path))
353→            .output()
354→            .map_err(|e| format!("failed to reveal {path}: {e}"))?;
355→        if !output.status.success() {
356→            let stderr = String::from_utf8_lossy(&output.stderr);
357→            return Err(format!("failed to reveal {path}: {stderr}"));
358→        }
359→        return Ok(());
360→    }
361→
362→    #[cfg(target_os = "linux")]
363→    {
364→        let parent = std::path::Path::new(&path)
365→            .parent()
366→            .map(|p| p.to_string_lossy().to_string())
367→            .unwrap_or_else(|| path.clone());
368→        let output = std::process::Command::new("xdg-open")
369→            .arg(&parent)
370→            .output()
371→            .map_err(|e| format!("failed to reveal: {e}"))?;
372→        if !output.status.success() {
373→            let stderr = String::from_utf8_lossy(&output.stderr);
374→            return Err(format!("failed to reveal: {stderr}"));
375→        }
376→        return Ok(());
377→    }
378→
379→    #[allow(unreachable_code)]
380→    Err("unsupported platform".to_string())
381→}
