 83→
 84→  useEffect(() => {
 85→    if (nav.stackDepth === 0) {
 86→      setQuery('');
 87→      setFilterValue('all');
 88→      setSelectedIndex(0);
 89→      setActionsOpen(false);
 90→      setQuickLookOpen(false);
 91→    }
 92→  }, [nav.stackDepth]);
 93→
 94→  const registrySections = useMemo(() => getSections(), []);
 95→
 96→  const filtered = useMemo(() => {
 97→    let sections = registrySections;
 98→    if (filterValue === 'commands') {
