654→      handleToggleFavorite,
655→    ],
656→  );
657→
658→  const activeDescendantId =
659→    allItems.length > 0 ? `list-item-${selectedIndex}` : undefined;
660→
661→  const contextLabel =
662→    nav.breadcrumbs.length > 0
663→      ? nav.breadcrumbs[nav.breadcrumbs.length - 1]!.label
664→      : 'Raycast';
665→
666→  const isCompact = !query.trim();
667→
668→  useEffect(() => {
669→    onCompactChange?.(isCompact);
670→  }, [
671→    isCompact,
672→    onCompactChange,
673→  ]);
674→
675→  return (
676→    <>
677→      <SearchBar
678→        value={query}
679→        onChange={handleQueryChange}
680→        activeDescendantId={activeDescendantId}
681→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
682→        dropdown={
683→          <SearchDropdown
684→            sections={searchFilterSections}
685→            value={filterValue}
686→            onChange={handleFilterChange}
687→          />
688→        }
689→      />
690→      <div
691→        className="command-palette__collapsible"
692→        aria-hidden={isCompact}
693→        inert={isCompact ? true : undefined}
694→      >
695→        <div className="command-palette__collapsible-inner">
696→          <div className="command-palette__body">
697→            <div className="command-palette__list-container">
698→              {allItems.length === 0 ? (
699→                <EmptyState
700→                  icon={<MagnifyingGlassIcon size={48} />}
701→                  title="No Results"
702→                  description="Try a different search term"
703→                />
704→              ) : (
705→                <List
706→                  itemCount={allItems.length}
707→                  onActiveIndexChange={handleActiveIndexChange}
708→                  onAction={handleDrillIn}
709→                  detail={
710→                    detail ? (
711→                      <Detail
712→                        markdown={detail.markdown}
713→                        metadata={
714→                          detail.metadata ? (
715→                            <DetailMetadata>
716→                              {detail.metadata.map(renderMetadataEntry)}
717→                            </DetailMetadata>
718→                          ) : undefined
719→                        }
720→                      />
721→                    ) : undefined
722→                  }
723→                >
724→                  {(() => {
725→                    let globalIndex = 0;
726→                    return (
727→                      <>
728→                        {calculatorResult && (
729→                          <ListSection title="Result">
730→                            <ListItem
731→                              index={globalIndex++}
732→                              title={`= ${calculatorResult}`}
733→                              subtitle={query.trim()}
734→                              icon={<CalculatorIcon />}
735→                              accessories={[{ text: 'Copy' }]}
736→                            />
737→                          </ListSection>
738→                        )}
739→                        {filtered.map(section => (
740→                          <ListSection
741→                            key={section.title}
742→                            title={section.title}
743→                          >
744→                            {section.items.map(item => {
745→                              const idx = globalIndex++;
746→                              const showStar =
747→                                isFavorite(item.id) &&
748→                                section.title !== 'Favorites';
749→                              const itemAccessories = showStar
750→                                ? [
751→                                    {
752→                                      icon: <StarFilledIcon size={12} />,
753→                                      tooltip: 'Favorite',
754→                                    },
755→                                    ...(item.accessories ?? []),
756→                                  ]
757→                                : item.accessories;
758→                              return (
759→                                <ListItem
760→                                  key={item.id}
761→                                  index={idx}
762→                                  title={item.title}
763→                                  subtitle={item.subtitle}
764→                                  icon={item.icon}
765→                                  accessories={itemAccessories}
766→                                  query={query || undefined}
767→                                />
768→                              );
769→                            })}
770→                          </ListSection>
771→                        ))}
772→                      </>
773→                    );
774→                  })()}
775→                </List>
776→              )}
777→            </div>
778→          </div>
779→          <ActionPanel
780→            contextLabel={contextLabel}
781→            actions={[
782→              {
783→                label: isCalculatorSelected ? 'Copy Result' : 'Open',
784→                shortcut: <Kbd keys={['↵']} />,
785→              },
786→              {
787→                label: 'Actions',
788→                shortcut: (
789→                  <Kbd
