#[tauri::command]
fn set_window_position_pref(
    state: tauri::State<'_, Mutex<WindowConfig>>,
    position: String,
) -> Result<(), String> {
    match position.as_str() {
        "center" | "top-third" => {
            if let Ok(mut config) = state.lock() {
                config.position_pref = position;
                Ok(())
            } else {
