  async revealInFinder(path: string) {
    const { invoke } = await import('@tauri-apps/api/core');
    await invoke('reveal_in_finder', { path });
  },
  async moveToTrash(path: string) {
    const { invoke } = await import('@tauri-apps/api/core');
    await invoke('move_to_trash', { path });
  },
};

