        }))
        .filter(s => s.items.length > 0);
      return [
        {
          title: 'Favorites',
          items: filteredFavs,
        },
        ...dedupedSections,
      ];
    }
    return filteredResult;
  }

  const pinnedSections: SectionData[] = [];
  const dedupIds = new Set<string>();

  if (favoriteItems.length > 0) {
    pinnedSections.push({
      title: 'Favorites',
      items: favoriteItems,
    });
